// --- Flatten ---
const nested = [[1, 2], [3, 4], [5, 6]];
console.log("Flat:", nested.flat());

const deepNested = [1, [2, [3, [4, [5]]]]];
console.log("Deep flat:", deepNested.flat(Infinity));

